import { useEffect } from "react";

const NUMBER_PATTERN = /-?\d[\d,]*(\.\d+)?/;

function animateResult(element: HTMLElement, nextText: string) {
  if (element.dataset.animatingResult === "true") return;
  const match = nextText.match(NUMBER_PATTERN);
  if (!match) return;

  const targetNumber = Number(match[0].replace(/,/g, ""));
  if (!Number.isFinite(targetNumber)) return;

  const previous = Number(element.dataset.lastResultValue || "0");
  const decimals = match[0].includes(".") ? match[0].split(".")[1].length : 0;
  const prefix = nextText.slice(0, match.index);
  const suffix = nextText.slice((match.index || 0) + match[0].length);
  const formatter = new Intl.NumberFormat(undefined, {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
  const start = performance.now();
  const duration = 650;

  element.dataset.animatingResult = "true";
  element.dataset.lastResultValue = String(targetNumber);

  const frame = (now: number) => {
    const progress = Math.min(1, (now - start) / duration);
    const eased = 1 - Math.pow(1 - progress, 3);
    const current = previous + (targetNumber - previous) * eased;
    element.textContent = `${prefix}${formatter.format(current)}${suffix}`;

    if (progress < 1) {
      requestAnimationFrame(frame);
    } else {
      element.textContent = nextText;
      element.dataset.animatingResult = "false";
    }
  };

  requestAnimationFrame(frame);
}

function watchResultElement(element: HTMLElement) {
  const initialText = element.textContent?.trim() || "";
  element.dataset.lastResultText = initialText;
  element.dataset.lastResultValue = "0";
  animateResult(element, initialText);

  const observer = new MutationObserver(() => {
    if (element.dataset.animatingResult === "true") return;
    const nextText = element.textContent?.trim() || "";
    if (!nextText || nextText === element.dataset.lastResultText) return;
    element.dataset.lastResultText = nextText;
    animateResult(element, nextText);
  });

  observer.observe(element, { childList: true, characterData: true, subtree: true });
  return observer;
}

export default function AnimatedResults() {
  useEffect(() => {
    const resultObservers = new Map<HTMLElement, MutationObserver>();

    const attach = () => {
      const markedResults = Array.from(document.querySelectorAll<HTMLElement>('[data-testid^="result-"]'));
      const visualResults = Array.from(document.querySelectorAll<HTMLElement>(".bg-gradient-to-br p"))
        .filter((element) => {
          const className = typeof element.className === "string" ? element.className : "";
          return className.includes("font-black") || className.includes("font-extrabold");
        });

      [...markedResults, ...visualResults].forEach((element) => {
        if (resultObservers.has(element)) return;
        resultObservers.set(element, watchResultElement(element));
      });
    };

    attach();
    const pageObserver = new MutationObserver(attach);
    pageObserver.observe(document.body, { childList: true, subtree: true });

    return () => {
      pageObserver.disconnect();
      resultObservers.forEach((observer) => observer.disconnect());
    };
  }, []);

  return null;
}
